function getValue(color: TinyColor, i: number, light?: boolean): number {
  const MAX = 1;
  const hsv = color.toHsv();
  // const greyScale = color.toHsl().l;
  let value: number;
  if (light) {
    // value = hsv.v + brightnessStep1 * i;
    const step = (MAX - hsv.v) / lightColorCount;
    value = hsv.v + step * i;
  } else {
    value = hsv.v - brightnessStep2 * i;
    // 3 阶
    // console.log((hsv.s + 0.1) ** 8);
    // const t = i / darkColorCount;
    // const MIN = hsv.v - 0.57;
    // value = bezier3(t, [
    //   { x: 0, y: hsv.v },
    //   { x: 1, y: ((hsv.v - MIN) * 0.1) / (hsv.s + 0.1) ** 16 + MIN }, // (hsv.s + 0.1) ** 16 为了让 s 大的下降快一些，s 小的下降慢一点
    //   { x: 3, y: ((hsv.v - MIN) * 0.1) / (hsv.s + 0.1) ** 16 + MIN },
    //   { x: 4, y: MIN },
    // ]).y;
  }
  if (value > MAX) {
    value = MAX;
  }
  // console.log(value);
  // if (value < 0.06) {
  //   value = 0.06;
  // }
  return Number(value.toFixed(2));
}

export default function (color: string): Color[] {
  const patterns: Array<Color> = [];
  const pColor = new TinyColor(color);
  for (const [i, level] of DEFAULT_COLOR_LEVELS.entries()) {
    const isLight = i <= lightColorCount;
    const hsv = pColor.toHsv();
    const colorString: string = new TinyColor({
      h: getHue(hsv, isLight ? lightColorCount - i : i - lightColorCount, isLight),
      s: getSaturation(hsv, isLight ? lightColorCount - i : i - lightColorCount, isLight),
      v: getValue(pColor, isLight ? lightColorCount - i : i - lightColorCount, isLight),
    }).toHexString();
    patterns.push({
      level,
      value: colorString,
    });
  }
  return patterns;
}
